module d_flip_flop(
    input       data_in     ,
    input       clk   ,
    input       reset ,

    output reg  q
);

   // D Flip-Flop with asynchronous reset
   always @(posedge clk or posedge reset) begin
       if (reset) begin
           q <= 1'b0;
       end else begin
           q <= data_in;
       end
   end

endmodule
